import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it } from 'vitest';
import { createPixelArt } from './pixelart-provider';

const TEST_BASE_URL = 'https://api.example.com/v1';

const server = createTestServer({
  [`${TEST_BASE_URL}/pixelart-v1/generate`]: {
    response: {
      type: 'json-value',
      body: {
        created: 1700000000,
        data: [{ b64_json: 'aGVsbG8=' }],
      },
    },
  },
});

describe('PixelArt provider', () => {
  it('creates image models via .image and .imageModel', () => {
    const provider = createPixelArt({ apiKey: 'test-key' });

    const imageModel = provider.image('pixelart-v1');
    const imageModel2 = provider.imageModel('pixelart-v2-pro');

    expect(imageModel.provider).toBe('pixelart.image');
    expect(imageModel.modelId).toBe('pixelart-v1');
    expect(imageModel2.modelId).toBe('pixelart-v2-pro');
    expect(imageModel.specificationVersion).toBe('v3');
  });

  it('configures baseURL and auth header correctly', async () => {
    const provider = createPixelArt({
      apiKey: 'test-api-key',
      baseURL: TEST_BASE_URL,
    });

    const model = provider.image('pixelart-v1');

    await model.doGenerate({
      prompt: 'A dragon in pixel art style',
      files: undefined,
      mask: undefined,
      n: 1,
      size: '512x512',
      seed: undefined,
      aspectRatio: undefined,
      providerOptions: {},
    });

    expect(server.calls[0].requestUrl).toBe(
      `${TEST_BASE_URL}/pixelart-v1/generate`,
    );
    expect(server.calls[0].requestMethod).toBe('POST');
    expect(server.calls[0].requestHeaders['authorization']).toBe(
      'Bearer test-api-key',
    );
    expect(await server.calls[0].requestBodyJson).toMatchObject({
      prompt: 'A dragon in pixel art style',
      n: 1,
      size: '512x512',
    });
  });

  it('includes user-agent header with version suffix', async () => {
    const provider = createPixelArt({
      apiKey: 'test-api-key',
      baseURL: TEST_BASE_URL,
    });

    await provider.image('pixelart-v1').doGenerate({
      prompt: 'test',
      files: undefined,
      mask: undefined,
      n: 1,
      size: undefined,
      seed: undefined,
      aspectRatio: undefined,
      providerOptions: {},
    });

    expect(server.calls[0].requestUserAgent).toContain('ai-sdk/pixelart/');
  });

  it('merges custom headers with auth header', async () => {
    const provider = createPixelArt({
      apiKey: 'test-api-key',
      baseURL: TEST_BASE_URL,
      headers: { 'x-custom': 'my-value' },
    });

    await provider.image('pixelart-v1').doGenerate({
      prompt: 'test',
      files: undefined,
      mask: undefined,
      n: 1,
      size: undefined,
      seed: undefined,
      aspectRatio: undefined,
      providerOptions: {},
    });

    expect(server.calls[0].requestHeaders['x-custom']).toBe('my-value');
    expect(server.calls[0].requestHeaders['authorization']).toContain(
      'Bearer test-api-key',
    );
  });

  it('throws NoSuchModelError for languageModel', () => {
    const provider = createPixelArt({ apiKey: 'test-key' });
    expect(() => provider.languageModel('gpt-4')).toThrowError(
      'No such languageModel',
    );
  });

  it('throws NoSuchModelError for embeddingModel', () => {
    const provider = createPixelArt({ apiKey: 'test-key' });
    expect(() => provider.embeddingModel('text-embedding-3-small')).toThrowError(
      'No such embeddingModel',
    );
  });
});

