import { FetchFunction } from '@ai-sdk/provider-utils';
import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it } from 'vitest';
import { PixelArtImageModel } from './pixelart-image-model';

const TEST_BASE_URL = 'https://api.example.com/v1';
const TEST_MODEL_ID = 'pixelart-v1';
const GENERATE_URL = `${TEST_BASE_URL}/${TEST_MODEL_ID}/generate`;

const defaultResponseBody = {
  created: 1700000000,
  data: [{ b64_json: 'aGVsbG8=' }],
};

function createBasicModel({
  headers,
  fetch,
  currentDate,
}: {
  headers?: () => Record<string, string | undefined>;
  fetch?: FetchFunction;
  currentDate?: () => Date;
} = {}) {
  return new PixelArtImageModel(TEST_MODEL_ID, {
    provider: 'pixelart.image',
    baseURL: TEST_BASE_URL,
    headers: headers ?? (() => ({ Authorization: 'Bearer test-key' })),
    fetch,
    _internal: { currentDate },
  });
}

describe('PixelArtImageModel', () => {
  const server = createTestServer({
    [GENERATE_URL]: {
      response: {
        type: 'json-value',
        body: defaultResponseBody,
      },
    },
  });

  describe('constructor', () => {
    it('exposes correct provider and model information', () => {
      const model = createBasicModel();

      expect(model.provider).toBe('pixelart.image');
      expect(model.modelId).toBe(TEST_MODEL_ID);
      expect(model.specificationVersion).toBe('v3');
      expect(model.maxImagesPerCall).toBe(4);
    });
  });

  describe('doGenerate', () => {
    it('sends prompt, n, and size in the request body', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt: 'A pixel knight',
        files: undefined,
        mask: undefined,
        n: 2,
        size: '256x256',
        seed: undefined,
        aspectRatio: undefined,
        providerOptions: {},
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        prompt: 'A pixel knight',
        n: 2,
        size: '256x256',
      });
    });

    it('includes seed when provided', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt: 'A pixel castle',
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        seed: 42,
        aspectRatio: undefined,
        providerOptions: {},
      });

      expect(await server.calls[0].requestBodyJson).toMatchObject({ seed: 42 });
    });

    it('sends style and pixel_density from providerOptions', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt: 'A retro spaceship',
        files: undefined,
        mask: undefined,
        n: 1,
        size: '512x512',
        seed: undefined,
        aspectRatio: undefined,
        providerOptions: {
          pixelArt: { style: 'retro', pixelDensity: 4 },
        },
      });

      expect(await server.calls[0].requestBodyJson).toMatchObject({
        prompt: 'A retro spaceship',
        size: '512x512',
        style: 'retro',
        pixel_density: 4,
      });
    });

    it('sends 8bit style from providerOptions', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt: 'A classic dungeon',
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        seed: undefined,
        aspectRatio: undefined,
        providerOptions: { pixelArt: { style: '8bit' } },
      });

      expect(await server.calls[0].requestBodyJson).toMatchObject({
        style: '8bit',
      });
    });

    it('omits style and pixel_density when not provided', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt: 'A simple sprite',
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        seed: undefined,
        aspectRatio: undefined,
        providerOptions: {},
      });

      const body = await server.calls[0].requestBodyJson;
      expect(body).not.toHaveProperty('style');
      expect(body).not.toHaveProperty('pixel_density');
    });

    it('returns base64 images from the response', async () => {
      server.urls[GENERATE_URL].response = {
        type: 'json-value',
        body: {
          created: 1700000000,
          data: [
            { b64_json: 'aGVsbG8=' },
            { b64_json: 'd29ybGQ=' },
          ],
        },
      };

      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt: 'Two sprites',
        files: undefined,
        mask: undefined,
        n: 2,
        size: undefined,
        seed: undefined,
        aspectRatio: undefined,
        providerOptions: {},
      });

      expect(result.images).toHaveLength(2);
      expect(result.images[0]).toBe('aGVsbG8=');
      expect(result.images[1]).toBe('d29ybGQ=');
    });

    it('includes seed in providerMetadata when returned by API', async () => {
      server.urls[GENERATE_URL].response = {
        type: 'json-value',
        body: {
          created: 1700000000,
          data: [{ b64_json: 'aGVsbG8=', seed: 99 }],
        },
      };

      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt: 'A seeded sprite',
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        seed: undefined,
        aspectRatio: undefined,
        providerOptions: {},
      });

      expect(result.providerMetadata?.pixelArt.images[0]).toMatchObject({
        seed: 99,
      });
    });

    it('omits seed from providerMetadata when not returned by API', async () => {
      server.urls[GENERATE_URL].response = {
        type: 'json-value',
        body: defaultResponseBody,
      };

      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt: 'A seedless sprite',
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        seed: undefined,
        aspectRatio: undefined,
        providerOptions: {},
      });

      expect(result.providerMetadata?.pixelArt.images[0]).not.toHaveProperty(
        'seed',
      );
    });

    it('emits an unsupported warning when aspectRatio is provided', async () => {
      server.urls[GENERATE_URL].response = {
        type: 'json-value',
        body: defaultResponseBody,
      };

      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt: 'A wide banner',
        files: undefined,
        mask: undefined,
        n: 1,
        size: '1024x512',
        seed: undefined,
        aspectRatio: '2:1',
        providerOptions: {},
      });

      expect(result.warnings).toContainEqual({
        type: 'unsupported',
        feature: 'aspectRatio',
        details: expect.stringContaining('PixelArt does not support aspectRatio'),
      });
    });

    it('includes timestamp, modelId, and headers in response metadata', async () => {
      server.urls[GENERATE_URL].response = {
        type: 'json-value',
        body: defaultResponseBody,
      };

      const testDate = new Date('2025-06-01T12:00:00Z');
      const model = createBasicModel({ currentDate: () => testDate });

      const result = await model.doGenerate({
        prompt: 'A timed sprite',
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        seed: undefined,
        aspectRatio: undefined,
        providerOptions: {},
      });

      expect(result.response).toStrictEqual({
        timestamp: testDate,
        modelId: TEST_MODEL_ID,
        headers: expect.any(Object),
      });
    });

    it('returns empty warnings array when no issues', async () => {
      server.urls[GENERATE_URL].response = {
        type: 'json-value',
        body: defaultResponseBody,
      };

      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt: 'A clean sprite',
        files: undefined,
        mask: undefined,
        n: 1,
        size: '512x512',
        seed: undefined,
        aspectRatio: undefined,
        providerOptions: {},
      });

      expect(result.warnings).toStrictEqual([]);
    });

    it('merges provider headers with per-request headers', async () => {
      server.urls[GENERATE_URL].response = {
        type: 'json-value',
        body: defaultResponseBody,
      };

      const model = createBasicModel({
        headers: () => ({
          Authorization: 'Bearer test-key',
          'x-provider-header': 'provider-value',
        }),
      });

      await model.doGenerate({
        prompt: 'Header test',
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        seed: undefined,
        aspectRatio: undefined,
        providerOptions: {},
        headers: { 'x-request-header': 'request-value' },
      });

      expect(server.calls[0].requestHeaders['x-provider-header']).toBe(
        'provider-value',
      );
      expect(server.calls[0].requestHeaders['x-request-header']).toBe(
        'request-value',
      );
    });

    it('handles API error responses', async () => {
      server.urls[GENERATE_URL].response = {
        type: 'error',
        status: 400,
        body: JSON.stringify({
          error: { message: 'Invalid prompt', code: 'invalid_prompt' },
        }),
      };

      const model = createBasicModel();

      await expect(
        model.doGenerate({
          prompt: '',
          files: undefined,
          mask: undefined,
          n: 1,
          size: undefined,
          seed: undefined,
          aspectRatio: undefined,
          providerOptions: {},
        }),
      ).rejects.toMatchObject({
        message: 'Invalid prompt',
        statusCode: 400,
      });
    });
  });
});

